import{_ as a,c as t,o,ae as e}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"從咖啡廳老闆到 80 億美元獨角獸：這位華人創業家拒絕 Stripe 12 億收購的豪賭","description":"15 歲離鄉背井到澳洲，從學霸變成「不會說英文的普通學生」。如今，他打造了估值 80 億美元的金融科技巨頭。","frontmatter":{"title":"從咖啡廳老闆到 80 億美元獨角獸：這位華人創業家拒絕 Stripe 12 億收購的豪賭","description":"15 歲離鄉背井到澳洲，從學霸變成「不會說英文的普通學生」。如今，他打造了估值 80 億美元的金融科技巨頭。","date":"2025-12-10T00:00:00.000Z","author":"Clement Tang","tags":["Airwallex","Jack Zhang","金融科技","跨境支付","創業故事","社群貼文"],"category":"articles","status":"published","lastModified":"2026-01-27T00:00:00.000Z"},"headers":[],"relativePath":"articles/2025-12-10-airwallex-founder-journey-social.md","filePath":"articles/2025-12-10-airwallex-founder-journey-social.md"}'),n={name:"articles/2025-12-10-airwallex-founder-journey-social.md"};function l(i,r,s,p,g,h){return o(),t("div",null,[...r[0]||(r[0]=[e('<h1 id="從咖啡廳老闆到-80-億美元獨角獸-這位華人創業家拒絕-stripe-12-億收購的豪賭" tabindex="-1">從咖啡廳老闆到 80 億美元獨角獸：這位華人創業家拒絕 Stripe 12 億收購的豪賭 <a class="header-anchor" href="#從咖啡廳老闆到-80-億美元獨角獸-這位華人創業家拒絕-stripe-12-億收購的豪賭" aria-label="Permalink to &quot;從咖啡廳老闆到 80 億美元獨角獸：這位華人創業家拒絕 Stripe 12 億收購的豪賭&quot;">​</a></h1><blockquote><p>15 歲離鄉背井到澳洲，從學霸變成「不會說英文的普通學生」。他在投資銀行工作十年後創業，前兩個產品失敗，銀行帳戶只剩六週現金。如今，他打造了估值 80 億美元的金融科技巨頭，年處理交易量超過 2,350 億美元。</p></blockquote><hr><h2 id="一切從一杯咖啡開始" tabindex="-1">一切從一杯咖啡開始 <a class="header-anchor" href="#一切從一杯咖啡開始" aria-label="Permalink to &quot;一切從一杯咖啡開始&quot;">​</a></h2><p>2015 年，墨爾本。</p><p>Jack Zhang（張亮）在投資銀行工作了十年，履歷光鮮亮麗——倫敦、香港、墨爾本，外匯交易、投資銀行，年薪優渥。</p><p>但他並不快樂。</p><p>「我試過大約 15 個副業，」Jack 回憶道。「從咖啡廳、進出口貿易、專案管理公司，到房地產開發。我只是想找到真正讓我滿足的事業。」</p><p>咖啡廳生意還不錯。他從巴西和印尼進口咖啡豆，從中國進口包裝材料。</p><p><strong>然後，問題來了。</strong></p><h2 id="一筆匯款-手續費吃掉-8" tabindex="-1">一筆匯款，手續費吃掉 8% <a class="header-anchor" href="#一筆匯款-手續費吃掉-8" aria-label="Permalink to &quot;一筆匯款，手續費吃掉 8%&quot;">​</a></h2><p>「我要匯 5,000 美元到巴西買咖啡豆，」Jack 說。「銀行收了我 3 天時間，還有將近 8% 的手續費和匯率損失。」</p><p><strong>400 美元。就這樣消失了。</strong></p><p>從中國進口包裝也是一樣。每次跨境付款都像在繳稅——高額手續費、糟糕的匯率、漫長的等待時間，還有完全不透明的收費結構。</p><p>「我在投資銀行做了十年外匯交易，我很清楚這些銀行的成本根本沒有這麼高，」Jack 憤怒地想。「為什麼小企業要被當成提款機？」</p><p>這個念頭在腦海中盤旋不去。</p><p>終於，在 2015 年，他和三位大學同學——Xijing Dai、Max Li、Lucy Liu——決定做一件事：</p><p><strong>打造一個讓跨境支付像本地轉帳一樣簡單便宜的平台。</strong></p><p>Airwallex 就這樣誕生了。</p><hr><h2 id="從學霸到「不會說英文的普通學生」" tabindex="-1">從學霸到「不會說英文的普通學生」 <a class="header-anchor" href="#從學霸到「不會說英文的普通學生」" aria-label="Permalink to &quot;從學霸到「不會說英文的普通學生」&quot;">​</a></h2><p>Jack 的創業之路，其實早在 15 歲就埋下了伏筆。</p><p>他出生在中國青島，一個有 800 萬人口的城市。父母都在銀行工作，他從小和祖父母一起長大。</p><p>「我熱愛數學和物理，」Jack 說。「在青島，我是全市前 100 名的學生。」</p><p>15 歲那年，父母把他送到澳洲讀書。</p><p>一夜之間，一切都變了。</p><p>「我從全市頂尖學生，變成了一個連英文都說不好的普通學生，」Jack 回憶。「那種落差感很難形容。」</p><p>但正是這段經歷，讓他學會了一件事：<strong>永不放棄，努力工作，保持樂觀。</strong></p><p>他在檸檬工廠打工、洗碗、調酒。他一邊適應新環境，一邊拼命學習。最終，他考上墨爾本大學，進入投資銀行，成為外匯交易員。</p><p>十年後，當他在倫敦、香港、墨爾本的金融中心穿梭時，表面上看起來已經「成功」了。</p><p>但內心深處，他知道這不是他想要的。</p><p>「我想做一些真正有意義的事情，」Jack 說。「不只是為了錢，而是為了解決一個真實的問題。」</p><hr><h2 id="前兩個產品完全失敗" tabindex="-1">前兩個產品完全失敗 <a class="header-anchor" href="#前兩個產品完全失敗" aria-label="Permalink to &quot;前兩個產品完全失敗&quot;">​</a></h2><p>Airwallex 的起步，遠比想像中艱難。</p><p>「跨境支付有太多種做法，」Jack 坦言。「我們前兩個產品完全選錯了方向，完全失敗。」</p><p>錢燒得很快。團隊士氣低落。投資人開始質疑。</p><p><strong>最糟糕的時刻，銀行帳戶只剩下六週的現金。</strong></p><p>Jack 沒有 Plan B。如果 Airwallex 失敗，他不知道接下來要做什麼。</p><p>更諷刺的是，Airwallex 的 CTO Xijing Dai 在加入之前已經失敗了四次創業。</p><p>「Xijing 告訴我，這是他最後一次創業了，」Jack 回憶。「如果再失敗，他就要認輸了。」</p><p>壓力山大。</p><p>就在彈盡糧絕的時刻，奇蹟發生了。</p><p><strong>紅杉資本和騰訊出手了。</strong></p><p>2016 年，Airwallex 拿到了 1,300 萬美元的 A 輪融資。</p><p>「那筆錢救了我們，」Jack 說。「更重要的是，它給了我們時間去找到正確的方向。」</p><hr><h2 id="第三次-終於找到了答案" tabindex="-1">第三次，終於找到了答案 <a class="header-anchor" href="#第三次-終於找到了答案" aria-label="Permalink to &quot;第三次，終於找到了答案&quot;">​</a></h2><p>有了資金和時間，團隊花了整整 2017 年重新思考產品。</p><p>這次，他們做對了。</p><p><strong>他們開發了一個 API 產品，讓企業可以用更低的費用、更快的速度收發國際款項。</strong></p><p>核心技術是什麼？</p><p><strong>繞過傳統銀行的 SWIFT 系統，建立自己的全球支付網路。</strong></p><p>Airwallex 在全球主要市場（美國、英國、歐洲、中國、澳洲、新加坡等）開設本地銀行帳戶，企業可以在一個平台上管理所有這些帳戶，進行跨境收付款。</p><p><strong>手續費？比傳統銀行低 90%。</strong></p><p><strong>速度？從 3-5 天縮短到 1-2 天，甚至即時到帳。</strong></p><p>2018 年 1 月，Airwallex 的交易量是 0 美元。</p><p><strong>到了 2018 年 12 月，交易量突破 10 億美元。</strong></p><p>爆炸式成長。</p><hr><h2 id="stripe-出價-12-億美元-他拒絕了" tabindex="-1">Stripe 出價 12 億美元，他拒絕了 <a class="header-anchor" href="#stripe-出價-12-億美元-他拒絕了" aria-label="Permalink to &quot;Stripe 出價 12 億美元，他拒絕了&quot;">​</a></h2><p>成功吸引了注意。</p><p>2019 年，全球支付巨頭 Stripe 的 CEO Patrick Collison 親自找上門，開出了 <strong>12 億美元的收購價</strong>。</p><p>當時，Airwallex 的年化營收只有 200 萬美元。</p><p>12 億美元 vs 200 萬營收，這是 <strong>600 倍的估值溢價</strong>。</p><p>任何理性的創業者都會接受這個 offer。</p><p><strong>Jack 拒絕了。</strong></p><p>「我們才剛剛開始，」Jack 後來解釋。「我們相信 Airwallex 可以成為一家偉大的獨立公司，而不只是別人的一部分。」</p><p>這個決定，在當時看來簡直瘋狂。</p><p>但 Jack 的賭注是對的。</p><hr><h2 id="從-100m-到-500m-花了-9-年-從-500m-到-1b-只花了-1-年" tabindex="-1">從 100M 到 500M 花了 9 年，從 500M 到 1B 只花了 1 年 <a class="header-anchor" href="#從-100m-到-500m-花了-9-年-從-500m-到-1b-只花了-1-年" aria-label="Permalink to &quot;從 100M 到 500M 花了 9 年，從 500M 到 1B 只花了 1 年&quot;">​</a></h2><p>快進到 2025 年。</p><p><strong>10 月，Airwallex 年化營收突破 10 億美元（ARR）。</strong></p><p>Jack 在社交媒體上分享了一個驚人的數據：</p><blockquote><p>「我們花了超過 6 年才達到 1 億美元 ARR，9 年才達到 5 億美元，但只花了 1 年就從 5 億翻倍到 10 億。」</p></blockquote><p>這就是指數型成長的威力。</p><p><strong>12 月，Airwallex 宣布完成 3.3 億美元 Series G 融資，估值達到 80 億美元。</strong></p><p>領投方是 Addition，參與方包括 T. Rowe Price、Activant、Lingotto、Robinhood Ventures 和 TIAA Ventures。</p><p><strong>核心數據一覽：</strong></p><ul><li><strong>年化營收</strong>：10 億美元+（YoY +90%）</li><li><strong>年化交易量</strong>：2,350 億美元+（YoY 翻倍）</li><li><strong>服務企業數</strong>：15 萬家+</li><li><strong>估值</strong>：80 億美元（比 6 個月前的 Series F 增長 30%）</li><li><strong>累計融資</strong>：15 億美元</li></ul><p>如果當初接受了 Stripe 的 12 億美元，Jack 和團隊能拿到多少？也許 3-5 億美元。</p><p>現在，Airwallex 的估值是 <strong>80 億美元</strong>。</p><p><strong>拒絕那筆收購，是 Jack 人生中最好的決定之一。</strong></p><hr><h2 id="設立舊金山雙總部-劍指美國市場" tabindex="-1">設立舊金山雙總部，劍指美國市場 <a class="header-anchor" href="#設立舊金山雙總部-劍指美國市場" aria-label="Permalink to &quot;設立舊金山雙總部，劍指美國市場&quot;">​</a></h2><p>Series G 融資的同時，Airwallex 宣布了一個重要戰略：</p><p><strong>將舊金山設為第二個全球總部（與墨爾本並列）。</strong></p><p>為什麼？</p><p>「舊金山是全球 AI 創新和人才的中心，」Jack 解釋。「我們要把核心產品、工程、戰略合作和市場團隊放在這裡。」</p><p>更激進的是：<strong>Airwallex 計劃在 2026-2029 年投資超過 10 億美元拓展美國市場。</strong></p><p>具體行動包括：</p><ul><li><strong>未來 12 個月內，美國團隊人數翻倍至 400+ 人</strong></li><li><strong>到 2026 年底，全球團隊擴張 50%</strong></li><li><strong>開發 AI 驅動的自動化財務工具</strong></li></ul><p>Airwallex 的野心很明確：<strong>在美國正面挑戰 Stripe、Adyen 等支付巨頭。</strong></p><hr><h2 id="從咖啡廳到-80-億美元的三個關鍵" tabindex="-1">從咖啡廳到 80 億美元的三個關鍵 <a class="header-anchor" href="#從咖啡廳到-80-億美元的三個關鍵" aria-label="Permalink to &quot;從咖啡廳到 80 億美元的三個關鍵&quot;">​</a></h2><p>回顧 Jack Zhang 和 Airwallex 的故事，有三個關鍵決策改變了一切。</p><h3 id="關鍵-1-解決自己遇到的真實痛點" tabindex="-1">關鍵 1：解決自己遇到的真實痛點 <a class="header-anchor" href="#關鍵-1-解決自己遇到的真實痛點" aria-label="Permalink to &quot;關鍵 1：解決自己遇到的真實痛點&quot;">​</a></h3><p>Jack 不是看到市場報告才決定做跨境支付。</p><p>他是因為 <strong>自己的咖啡廳生意被高額手續費折磨</strong>，才憤而創業。</p><p>「最好的創業點子，來自你自己深刻體驗過的痛苦，」Jack 說。</p><p>這種「切身之痛」帶來兩個優勢：</p><ol><li><strong>你比任何人都了解問題</strong></li><li><strong>你有強烈的動機去解決它</strong></li></ol><h3 id="關鍵-2-失敗兩次後-勇敢承認並重新開始" tabindex="-1">關鍵 2：失敗兩次後，勇敢承認並重新開始 <a class="header-anchor" href="#關鍵-2-失敗兩次後-勇敢承認並重新開始" aria-label="Permalink to &quot;關鍵 2：失敗兩次後，勇敢承認並重新開始&quot;">​</a></h3><p>前兩個產品失敗時，Jack 沒有硬撐。</p><p>「我們花了一整年時間推翻重來，」Jack 坦言。「那段時間很痛苦，但如果我們繼續做錯誤的產品，只會死得更慘。」</p><p><strong>承認失敗比堅持錯誤更需要勇氣。</strong></p><h3 id="關鍵-3-拒絕誘惑-堅持長期願景" tabindex="-1">關鍵 3：拒絕誘惑，堅持長期願景 <a class="header-anchor" href="#關鍵-3-拒絕誘惑-堅持長期願景" aria-label="Permalink to &quot;關鍵 3：拒絕誘惑，堅持長期願景&quot;">​</a></h3><p>12 億美元的收購 offer，足以讓 Jack 和團隊財務自由。</p><p>但 Jack 看到了更大的可能性。</p><p>「我們不只想賣掉公司套現，」Jack 說。「我們想打造一家真正改變全球企業資金流動方式的公司。」</p><p><strong>短期誘惑 vs 長期願景，他選擇了後者。</strong></p><hr><h2 id="下一步-成為全球企業的「金融操作系統」" tabindex="-1">下一步：成為全球企業的「金融操作系統」 <a class="header-anchor" href="#下一步-成為全球企業的「金融操作系統」" aria-label="Permalink to &quot;下一步：成為全球企業的「金融操作系統」&quot;">​</a></h2><p>Airwallex 的終極目標是什麼？</p><p><strong>成為全球企業的金融操作系統（Financial OS）。</strong></p><p>就像 Shopify 是電商的操作系統，Salesforce 是 CRM 的操作系統，Airwallex 想成為全球資金流動的操作系統。</p><p>目前，Airwallex 的產品矩陣包括：</p><ul><li><strong>跨境支付</strong>：收付款、換匯、全球帳戶</li><li><strong>支付處理</strong>：接受信用卡、數位錢包等付款方式</li><li><strong>企業卡</strong>：虛擬卡、實體卡，全球消費</li><li><strong>資金管理</strong>：現金流優化、收益增強</li><li><strong>薪資發放</strong>：全球員工薪資處理</li><li><strong>API 平台</strong>：嵌入式金融服務</li></ul><p><strong>核心競爭力：</strong></p><ol><li><strong>全球化網路</strong>：在 130+ 個國家運營，93% 的交易繞過 SWIFT</li><li><strong>技術驅動</strong>：API 優先，快速整合</li><li><strong>價格優勢</strong>：比傳統銀行便宜 90%</li><li><strong>數據洞察</strong>：基於海量交易數據的智慧建議</li></ol><hr><h2 id="給創業者的三個啟示" tabindex="-1">給創業者的三個啟示 <a class="header-anchor" href="#給創業者的三個啟示" aria-label="Permalink to &quot;給創業者的三個啟示&quot;">​</a></h2><h3 id="啟示-1-最好的創業靈感來自切身之痛" tabindex="-1">啟示 1：最好的創業靈感來自切身之痛 <a class="header-anchor" href="#啟示-1-最好的創業靈感來自切身之痛" aria-label="Permalink to &quot;啟示 1：最好的創業靈感來自切身之痛&quot;">​</a></h3><p>不要去做「市場報告說很熱門」的事。</p><p>去做「你自己深刻痛過、恨過、想要改變」的事。</p><p>Jack 不是因為看到 fintech 很夯才創業，而是因為每次匯款都在心裡罵髒話。</p><p><strong>那種憤怒，才是最強大的創業動力。</strong></p><h3 id="啟示-2-失敗是必經之路-關鍵是速度" tabindex="-1">啟示 2：失敗是必經之路，關鍵是速度 <a class="header-anchor" href="#啟示-2-失敗是必經之路-關鍵是速度" aria-label="Permalink to &quot;啟示 2：失敗是必經之路，關鍵是速度&quot;">​</a></h3><p>Airwallex 前兩個產品失敗了。Jack 的 CTO 之前失敗了四次。</p><p>但他們沒有因此放棄，而是 <strong>快速學習、快速調整、快速重來</strong>。</p><p>成功的創業者不是不會失敗，而是 <strong>失敗得比別人快，學得比別人快</strong>。</p><h3 id="啟示-3-長期主義才能贏得大局" tabindex="-1">啟示 3：長期主義才能贏得大局 <a class="header-anchor" href="#啟示-3-長期主義才能贏得大局" aria-label="Permalink to &quot;啟示 3：長期主義才能贏得大局&quot;">​</a></h3><p>12 億美元的收購價很誘人。</p><p>但如果 Jack 當初接受了，就不會有今天估值 80 億美元的 Airwallex。</p><p><strong>真正的大機會，需要你有勇氣拒絕短期誘惑。</strong></p><hr><h2 id="從咖啡廳到金融基礎設施的啟示" tabindex="-1">從咖啡廳到金融基礎設施的啟示 <a class="header-anchor" href="#從咖啡廳到金融基礎設施的啟示" aria-label="Permalink to &quot;從咖啡廳到金融基礎設施的啟示&quot;">​</a></h2><p>Jack Zhang 的故事，是一個關於「永不放棄」的故事。</p><p>15 歲到異國他鄉，從學霸變普通學生——他沒有放棄。</p><p>投資銀行工作十年，內心不滿足——他沒有放棄尋找意義。</p><p>前兩個產品失敗，只剩六週現金——他沒有放棄創業夢想。</p><p>Stripe 出價 12 億美元——他沒有放棄長期願景。</p><p><strong>每一次選擇，都是在選擇「更難的路」。</strong></p><p>但也正是這些選擇，讓他從一個「不會說英文的普通學生」，變成掌管 80 億美元金融科技巨頭的 CEO。</p><p>今天，Airwallex 每年處理超過 2,350 億美元的交易，服務 15 萬家企業，團隊遍布全球 20+ 個辦公室。</p><p>從青島到澳洲，從咖啡廳到金融基礎設施，Jack Zhang 用十年時間證明了一件事：</p><p><strong>最好的創業，始於解決你自己的問題。</strong><strong>最偉大的公司，建立在永不放棄的信念上。</strong></p><p>而這個故事，才剛剛開始。</p><hr><h2 id="關鍵數據總覽" tabindex="-1">關鍵數據總覽 <a class="header-anchor" href="#關鍵數據總覽" aria-label="Permalink to &quot;關鍵數據總覽&quot;">​</a></h2><p><strong>Airwallex 里程碑（2015-2025）：</strong></p><ul><li><strong>2015</strong>：在墨爾本成立</li><li><strong>2016</strong>：Series A（1,300 萬美元，紅杉+騰訊）</li><li><strong>2018</strong>：交易量從 0 到 10 億美元</li><li><strong>2019</strong>：拒絕 Stripe 12 億美元收購</li><li><strong>2021</strong>：ARR 達 1 億美元（6 年）</li><li><strong>2024</strong>：ARR 達 5 億美元（9 年）</li><li><strong>2025 年 10 月</strong>：<strong>ARR 突破 10 億美元</strong>（只花 1 年翻倍）</li><li><strong>2025 年 12 月</strong>：<strong>Series G（3.3 億美元，估值 80 億美元）</strong></li></ul><p><strong>Series G 融資細節（2025 年 12 月）：</strong></p><ul><li><strong>融資金額</strong>：3.3 億美元</li><li><strong>估值</strong>：80 億美元（比 6 個月前 +30%）</li><li><strong>領投</strong>：Addition</li><li><strong>參與方</strong>：T. Rowe Price, Activant, Lingotto, Robinhood Ventures, TIAA Ventures</li><li><strong>累計融資</strong>：15 億美元</li></ul><p><strong>核心業務數據（2025）：</strong></p><ul><li><strong>年化營收</strong>：10 億美元+（YoY +90%）</li><li><strong>年化交易量</strong>：2,350 億美元+（YoY 翻倍）</li><li><strong>服務企業數</strong>：15 萬家+</li><li><strong>全球辦公室</strong>：20+ 個城市</li><li><strong>支持貨幣</strong>：130+ 個國家</li><li><strong>繞過 SWIFT 比例</strong>：93%</li></ul><p><strong>美國擴張計劃（2026-2029）：</strong></p><ul><li><strong>投資額</strong>：10 億美元+</li><li><strong>美國團隊</strong>：12 個月內翻倍至 400+ 人</li><li><strong>全球團隊</strong>：2026 年底前擴張 50%</li><li><strong>雙總部</strong>：墨爾本 + 舊金山</li></ul><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><ol><li><a href="https://www.unimelb.edu.au/alumni/stay-connected/news-and-stories/jack-zhang-finding-success" target="_blank" rel="noreferrer">Jack Zhang – Finding success in the pursuit of happiness - University of Melbourne</a></li><li><a href="https://thefinanser.com/2025/07/the-story-of-jack-zhang-and-airwallex" target="_blank" rel="noreferrer">The story of Jack Zhang and Airwallex - Chris Skinner&#39;s blog</a></li><li><a href="https://www.tatlerasia.com/power-purpose/wealth/jack-zhang-airwallex-interview" target="_blank" rel="noreferrer">Airwallex CEO Jack Zhang on how he built a global financial platform - Tatler Asia</a></li><li><a href="https://www.airwallex.com/newsroom/awx-raises-usd330m-series-g-at-usd8b-valuation-establishes-sf-as-dual-global-hq" target="_blank" rel="noreferrer">Airwallex Raises $330M Series G at $8B Valuation - Business Wire</a></li><li><a href="https://fortune.com/2025/11/03/airwallex-1-billion-annualized-revenue-fintech-payments-ramp-stripe-jack-zhang/" target="_blank" rel="noreferrer">Exclusive: Airwallex crosses $1 billion in annualized revenue - Fortune</a></li><li><a href="https://www.thetwentyminutevc.com/jack-zhang" target="_blank" rel="noreferrer">Airwallex CEO &amp; Co-Founder, Jack Zhang: The Angel That Turned $1M into $1BN - The Twenty Minute VC</a></li></ol><hr><h2 id="更新記錄" tabindex="-1">更新記錄 <a class="header-anchor" href="#更新記錄" aria-label="Permalink to &quot;更新記錄&quot;">​</a></h2><ul><li><strong>2025-12-10：</strong> 建立社群貼文版本，以台灣商業周刊風格撰寫 Airwallex 創辦人 Jack Zhang 的創業故事</li></ul><hr>',166)])])}const d=a(n,[["render",l]]);export{u as __pageData,d as default};
